import React, { useState, useEffect } from 'react';
import { MapContainer, TileLayer, Marker, Popup, Tooltip } from 'react-leaflet';
import 'leaflet/dist/leaflet.css';
import L from 'leaflet';
import { Link, useNavigate } from 'react-router-dom';
import './Map.css';
import { sectionsData } from '../sectionsData';
import { locationPins } from '../locationPins';
import Push from 'push.js';
import sectionIcon from '../assets/mark.svg';
import toilet from '../assets/toilet.svg';
import museum from '../assets/museum.svg';
import show from '../assets/show.svg';
import yoga from '../assets/yoga.svg';
import pilates from '../assets/pilates.svg';
import breakdance from '../assets/break.svg';
import discdog from '../assets/disc-dog.svg';
import dogtrekking from '../assets/dog-trekking.svg';
import tent from '../assets/tent.svg';
import vrglasses from '../assets/vr-glasses.svg';
import orienteering from '../assets/orienteering.svg';
import vertical from '../assets/vertical.svg';
import bike from '../assets/bike.svg';
import trekking from '../assets/trekking.svg';
import slack from '../assets/tightrope.svg';
import calisthenics from '../assets/calisthenics.svg';
import parkour from '../assets/parkour.svg';
import InfoModal from './InfoModal';

delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: 'https://unpkg.com/leaflet@1.7.1/dist/images/marker-icon-2x.png',
  iconUrl: 'https://unpkg.com/leaflet@1.7.1/images/marker-icon.png',
  shadowUrl: 'https://unpkg.com/leaflet@1.7.1/dist/images/marker-shadow.png',
});

const createIcon = (iconUrl, backgroundColor) => {
  return new L.DivIcon({
    html: `
      <div style="background-color: ${backgroundColor}; border: 2px black; border-radius: 50%; width: 35px; height: 35px; display: flex; align-items: center; justify-content: center; box-shadow: 0px 8px 15px rgba(0, 0, 0, 0.3); z-index: '900'">
        <img src="${iconUrl}" style="width: 25px; height: 25px;  z-index: '1000'"" />
      </div>
    `,
    className: '',
    iconSize: [40, 40],
    iconAnchor: [17.5, 17.5], // Centra l'icona nel cerchio
    popupAnchor: [0, -17.5] // Posiziona il popup sopra l'icona

  });
};

const iconMapping = {
  'toilet': toilet,
  'show': show,
  'museum': museum,
  'yoga': yoga,
  'pilates': pilates,
  'breakdance': breakdance,
  'discdog': discdog,
  'dogtrekking': dogtrekking,
  'tent': tent,
  'vrglasses': vrglasses,
  'orienteering': orienteering,
  'vertical': vertical,
  'bike': bike,
  'trekking': trekking,
  'slack': slack,
  'calisthenics': calisthenics,
  'parkour': parkour
  // Add other mappings as needed
};

const createSecIcon = (iconUrl) => {
  return new L.DivIcon({
    html: `
    <div style="width: 40px; height: 50px; display: flex; align-items: center; justify-content: center; z-index: 1000">
      <img src="${iconUrl}" style="width: 40px; height: 45px; z-index: 2000" />
    </div>
    `,
    className: '',
    iconSize: [40, 40],
    iconAnchor: [20, 40],
    popupAnchor: [0, -40]
  });
};

const deviceIcon = new L.DivIcon({
  html: '<div style="background-color: darkred; z-index: 3000; width: 12px; height: 12px; border-radius: 50%;"></div>',
  className: '',
  iconSize: [12, 12],
  iconAnchor: [6, 6]
});

const Map = ({ user, selectedBlocks, onCheckboxChange, showWarning, timeRemaining, onEventMessage, isAppAvailable, additionalPins, isAppStarted }) => {
  const navigate = useNavigate();
  const [devicePosition, setDevicePosition] = useState(null);
  const [isGpsEnabled, setIsGpsEnabled] = useState(false);
  const [showGpsPopup, setShowGpsPopup] = useState(false);
  const [hasShownGpsPopup, setHasShownGpsPopup] = useState(() => {
    return sessionStorage.getItem('hasShownGpsPopup') === 'true';
  });
  const [filter, setFilter] = useState('all');
  const [submittedBlocks, setSubmittedBlocks] = useState({});
  const [deviceMotion, setDeviceMotion] = useState(null);
  const [deviceCompass, setDeviceCompass] = useState(null);

  useEffect(() => {
    const storedBlocks = localStorage.getItem(`submittedBlocks-${user.username}`);
    if (storedBlocks) {
      setSubmittedBlocks(JSON.parse(storedBlocks));
    }
  }, []);
  
  useEffect(() => {
    const checkGpsEnabled = () => {
      if ("geolocation" in navigator) {
        navigator.geolocation.getCurrentPosition(
          (position) => {
            setIsGpsEnabled(true);
            setDevicePosition([position.coords.latitude, position.coords.longitude]);
            sessionStorage.setItem('hasShownGpsPopup', 'true');
          },
          (error) => {
            setIsGpsEnabled(false);
            if (!hasShownGpsPopup) {
              setShowGpsPopup(true);
              setHasShownGpsPopup(true);
              sessionStorage.setItem('hasShownGpsPopup', 'true');
            }
            // console.error('Geolocation error:', error);
          }
        );
      } else {
        setIsGpsEnabled(false);
        if (!hasShownGpsPopup) {
          setShowGpsPopup(true);
          setHasShownGpsPopup(true);
          sessionStorage.setItem('hasShownGpsPopup', 'true');
        }
      }
    };
  
    const handleMotion = (event) => {
      const { acceleration, rotationRate } = event;
      setDeviceMotion({
        acceleration: {
          x: acceleration.x,
          y: acceleration.y,
          z: acceleration.z,
        },
        rotationRate: {
          alpha: rotationRate.alpha,
          beta: rotationRate.beta,
          gamma: rotationRate.gamma,
        },
      });
    };
  
    const handleCompass = (event) => {
      setDeviceCompass(event.webkitCompassHeading || event.alpha);
    };
  
    checkGpsEnabled();
    const interval = setInterval(checkGpsEnabled, 5000);
  
    if (window.DeviceMotionEvent) {
      window.addEventListener('devicemotion', handleMotion);
    }
  
    if (window.DeviceOrientationEvent) {
      window.addEventListener('deviceorientation', handleCompass);
    }
  
    return () => {
      clearInterval(interval);
      window.removeEventListener('devicemotion', handleMotion);
      window.removeEventListener('deviceorientation', handleCompass);
    };
  }, [hasShownGpsPopup]);

  useEffect(() => {
        if ('Notification' in window) {
            if (Notification.permission !== 'granted') {
                Notification.requestPermission().then(permission => {
                    if (permission === 'granted') {
                        console.log('Permesso per le notifiche concesso');
                    } else {
                        console.log('Permesso per le notifiche negato');
                    }
                });
            }
        } else {
            console.log('Le notifiche non sono supportate da questo browser');
        }
    }, []);
    

  const handleSectionClick = (sectionId) => {
    navigate('/sections', { state: { sectionId } });
  };

  const getEventMessage = (pin) => {
  const now = new Date();
  const startTime = new Date(pin.start);
  const endTime = new Date(pin.end);
  const timeDiffStart = startTime - now;
  const timeDiffEnd = endTime - now;

  const formatTime = (timeDiff) => {
    const hours = Math.floor(timeDiff / (1000 * 60 * 60));
    const minutes = Math.floor((timeDiff % (1000 * 60 * 60)) / (1000 * 60));
    if (hours === 0) {
      return `${minutes}m`;
    } else {
      return `${hours}h ${minutes}m`;
    }
  };

  const timeStart = new Date(pin.start).toLocaleTimeString('it-IT', { 
    hour: '2-digit', 
    minute: '2-digit' 
  });

  if (timeDiffStart <= 0) {
    return {
      text: `Evento già iniziato alle ${timeStart} e finisce tra ${formatTime(timeDiffEnd)}`,
      type: 'orange'
    };
  } else {
    return {
      text: `Affrettati, mancano ${formatTime(timeDiffStart)} all'inizio dell'evento`,
      type: 'green'
    };
  }
};

  const handlePinClick = (pin) => {
    const message = getEventMessage(pin);
    onEventMessage(message);
  };

  const handleFilterChange = (event) => {
    setFilter(event.target.value);
  };

  return (
    <div className="map-container">
      <InfoModal />
      <MapContainer center={[43.674311, 12.518325]} zoom={15} style={{ height: '100%', width: '100%', zIndex: '800' }}>
        <TileLayer
          url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
          attribution='© <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a>'
        />
        {(filter === 'all' || filter === 'section') && sectionsData
        .filter(section => isAppStarted || section.isVisible)
        .map(section => (
          <Marker key={section.id} position={section.position} icon={createSecIcon(sectionIcon)}>
            <Tooltip direction="left" offset={[14, -20]} opacity={1} permanent className="custom-tooltip">
              <span>{section.id}</span>
            </Tooltip>
            <Popup>
              <h3 onClick={() => handleSectionClick(section.id)} style={{ cursor: 'pointer', color: 'darkred', textDecoration: 'underline' }}>
                {section.name}
              </h3>
              {section.description && section.description.trim() !== '' && (
                <p>{section.description}</p>
              )}
              <p>
                <a 
                  href={`https://www.google.com/maps/search/?api=1&query=${section.position[0]},${section.position[1]}`}
                  target="_blank" 
                  rel="noopener noreferrer" 
                  style={{ textDecoration: 'underline', color: 'darkred' }}
                >
                  Indicazioni</a></p>
              {isAppStarted && section.blocks.map(block => (
                <div key={block.name} style={{display: 'flex', flexDirection: 'row', alignItems: 'center', marginBottom: '5px'}}>
                  <span className={`color-dot ${block.color}`}></span>
                  <label style={{display: 'flex', flexDirection: 'row', alignItems: 'center', fontSize:'medium'}}>
                    <input
                      type="checkbox"
                      className="custom-checkbox"
                      checked={selectedBlocks.includes(block.name)}
                      onChange={() => onCheckboxChange(block.name)}
                      disabled={
                        localStorage.getItem(`submittedBlocks-${user.username}`)
                            ? JSON.parse(localStorage.getItem(`submittedBlocks-${user.username}`)).includes(block.name)
                            : false
                      }
                    />
                    {block.name}
                  </label>
                </div>
              ))}
            </Popup>
          </Marker>
        ))}
        {(filter === 'all' || filter === 'active') && additionalPins.map(pin => {
            // Rimuovi la stringa _1, _2 o _3 dal titolo
            const title = pin.title.replace(/(_1|_2|_3)$/, '');
            const iconUrl = iconMapping[pin.iconUrl.toLowerCase()] || pin.iconUrl; // Use the mapped icon or the original URL if not found
            return (
                <Marker key={pin.title} position={pin.position} icon={createIcon(iconUrl, pin.backgroundColor)} eventHandlers={{ click: () => handlePinClick(pin) }}>
                    <Popup>
                        <h3>{title}</h3>
                        <p>{pin.time}</p>
                        <p>{pin.description}</p>
                        <p><a 
                            href={`https://www.google.com/maps/search/?api=1&query=${pin.position[0]},${pin.position[1]}`}  
                            target="_blank" 
                            rel="noopener noreferrer" 
                            style={{ textDecoration: 'underline', color: 'darkred' }}
                        >Indicazioni</a></p>
                    </Popup>
                </Marker>
            );
        })}
        {(filter === 'all' || filter === 'location') && locationPins.map(pin => (
          <Marker key={pin.id} position={pin.position} icon={createIcon(pin.iconUrl, pin.backgroundColor)}>
            <Popup>
              <h3>{pin.title}</h3>
              {pin.description !== "" && <p>{pin.description}</p>}
              <p><a 
                  href={`https://www.google.com/maps/search/?api=1&query=${pin.position[0]},${pin.position[1]}`}
                  target="_blank" 
                  rel="noopener noreferrer" 
                  style={{ textDecoration: 'underline', color: 'darkred' }}
                >{pin.address}</a></p>
                </Popup>
              </Marker>
            ))}
            {isGpsEnabled && devicePosition && (
              <Marker position={devicePosition} icon={deviceIcon}>
                <Popup>
                  <h3>Tu sei qui</h3>
                  {/* <p>Latitudine: {devicePosition[0]}</p>
                  <p>Longitudine: {devicePosition[1]}</p> */}
                </Popup>
              </Marker>
            )}
          </MapContainer>
          <select onChange={handleFilterChange} className="map-filter">
            <option value="all">Tutti</option>
            <option value="location">Luoghi</option>
            <option value="active">Eventi</option>
            <option value="section">Settori</option>
          </select>
          {showWarning && (
            <div className="warning-popup">
              Affrettati a inviare i blocchi, la gara sta per finire! Tempo rimanente: {timeRemaining}
            </div>
          )}
          {showGpsPopup && (
            <div className="gps-popup">
              <p>Per favore, attiva il GPS per visualizzare la tua posizione sulla mappa.</p>
              <button onClick={() => setShowGpsPopup(false)}>OK</button>
            </div>
          )}
        </div>
      );
    };

    export default Map;