import React, { useEffect, useState } from 'react';
import './Results.css';
import { appConfig } from '../config';

const Results = ({ isAppAvailable }) => {
  const [displayScores, setDisplayScores] = useState([]);
  const [showTeams, setShowTeams] = useState(false); // Nuovo stato per toggle

  const fetchScores = async () => {
    try {
      const endpoint = showTeams 
        ? 'https://anxwjec2ct.eu-central-1.awsapprunner.com/mover/scoresByTeams'
        : 'https://anxwjec2ct.eu-central-1.awsapprunner.com/mover/scores';

      const response = await fetch(endpoint);
      if (!response.ok) throw new Error('Errore nel recupero punteggi');

      const data = await response.json();
      const sortedScores = data.sort((a, b) => b.finalScore - a.finalScore);
      setDisplayScores(sortedScores);
      localStorage.setItem(`scores_${showTeams ? 'teams' : 'users'}`, JSON.stringify(sortedScores));
    } catch (error) {
      console.error('Errore:', error);
      alert('Errore nel recupero punteggi');
    }
  };

  useEffect(() => {
  const now = new Date();
  const deadlineWithBuffer = new Date(appConfig.deadline.getTime() + 60 * 60 * 1000); // +1 ora

  if (!isAppAvailable && now >= new Date(appConfig.deadline.getTime() + 30 * 60 * 1000)) {
    // Prova prima localStorage, poi fetch
    const storageKey = `scores_${showTeams ? 'teams' : 'users'}`;
    const savedScores = localStorage.getItem(storageKey);
    if (savedScores) {
      setDisplayScores(JSON.parse(savedScores));
    } else {
      fetchScores();
    }

    const intervalId = setInterval(() => {
      const currentTime = new Date();
      if (currentTime <= deadlineWithBuffer) {
        fetchScores();
      } else {
        clearInterval(intervalId);
      }
    }, 15 * 60 * 1000); // 15 minuti

    return () => clearInterval(intervalId);
  }
}, [isAppAvailable, appConfig.deadline, showTeams]);

  const handleToggle = () => {
    setShowTeams(!showTeams);
  };

  const getDisplayName = (score) => {
    return showTeams ? score.teamName : score.username;
  };

  return (
    <div className="results-container">
      <h2>Risultati</h2>
      
      <div className="toggle-section">
        <button 
          className={`toggle-button ${!showTeams ? 'active' : ''}`}
          onClick={handleToggle}
        >
          Risultati Individuali
        </button>
        <button 
          className={`toggle-button ${showTeams ? 'active' : ''}`}
          onClick={handleToggle}
        >
          Risultati Squadre
        </button>
      </div>

      {displayScores.length === 0 ? (
        <p className="no-scores">Punteggi in fase di calcolo!</p>
      ) : (
        <ul>
          {displayScores.map((result, index) => (
            <li key={index}>
              {index + 1}. {getDisplayName(result)}: {result.finalScore}
            </li>
          ))}
        </ul>
      )}
    </div>
  );
};

export default Results;