import React, { useState } from "react";
import Modal from 'react-modal';
import './Programma.css';
import wzpIcon from '../assets/wzpimage.svg';
import telIcon from '../assets/phone.svg';
import InfoModal from './InfoModal';

const Programma = ({ additionalPins }) => {

  // Ordina gli eventi per data di inizio
  const sortedEvents = [...additionalPins].sort((a, b) => new Date(a.start) - new Date(b.start));

  const formatDate = (isoString) => {
    const date = new Date(isoString);
    return date.toLocaleDateString('it-IT', { 
      day: '2-digit', 
      month: '2-digit', 
      year: 'numeric' 
    });
  };

  const formatTime = (isoString) => {
    const date = new Date(isoString);
    return date.toLocaleTimeString('it-IT', { 
      hour: '2-digit', 
      minute: '2-digit' 
    });
  };

  return (
    <div className="programma-container">
    <InfoModal />
      <h2>Programma Eventi</h2>
      <div className="program-list">
        {sortedEvents.map(event => {
          // Rimuovi la stringa _1, _2 o _3 dal titolo
          const title = event.title.replace(/(_1|_2|_3)$/, '');
          const startDate = new Date(event.start);
          const endDate = new Date(event.end);
          return (
            <div className="evento-item" key={event.title}>
              <div className="evento-header">
                <strong>{formatDate(event.start)} | {formatTime(event.start)} - {formatTime(event.end)}</strong>
                <h3>{title}</h3>
                <a href={`https://www.google.com/maps/search/?api=1&query=${event.position[0]},${event.position[1]}`} target="_blank" rel="noopener noreferrer">
                  Indicazioni
                </a>
                <p>{event.description}</p>
              </div>
              {/* <a href={`https://www.google.com/maps/search/?api=1&query=${event.position[0]},${event.position[1]}`} target="_blank" rel="noopener noreferrer">
                            Indirizzo
                        </a> */}
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default Programma;