import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import Results from './Results';
import './Admin.css';

const AdminPage = () => {
  const navigate = useNavigate();

  useEffect(() => {
    const user = JSON.parse(localStorage.getItem('user'));
    if (!user || user.username !== 'mover-admin') {
      navigate('/');
    }
  }, [navigate]);

  const [eventData, setEventData] = useState({
    title: '',
    time: '',
    description: '',
    address: '',
    position: ['', ''],
    start: '',
    end: '',
    iconUrl: '',
    backgroundColor: '',
  });

  const [deleteTitle, setDeleteTitle] = useState('');
  const [displayScores, setDisplayScores] = useState([]);
  const [displayTeams, setDisplayTeams] = useState([]);
  const [displayScoresResults, setDisplayScoresResults] = useState([]);

  const [teamData, setTeamData] = useState({
    teamName: '',
    memberNames: '',
  });

  const [addUserData, setAddUserData] = useState({
    teamName: '',
    userName: '',
  });

  const fetchScores = async () => {
    try {
      const response = await fetch('https://anxwjec2ct.eu-central-1.awsapprunner.com/mover/scores');
      if (!response.ok) throw new Error('Errore nel recupero punteggi');
      
      const data = await response.json();
      console.log('RISPOSTA API /mover/scores:', data);
      setDisplayScores(data.sort((a, b) => b.finalScore - a.finalScore));
    } catch (error) {
      console.error('Errore:', error);
      alert('Errore nel recupero punteggi');
    }
  };
  const fetchTeams = async () => {
    try {
      const response = await fetch('https://anxwjec2ct.eu-central-1.awsapprunner.com/mover/scoresByTeams');
      if (!response.ok) throw new Error('Errore nel recupero punteggi team');

      const data = await response.json();
      setDisplayTeams(data.sort((a, b) => b.finalScore - a.finalScore));
    } catch (error) {
      console.error('Errore:', error);
      alert('Errore nel recupero punteggi team');
    }
  };
  
  const handleChange = (e) => {
    const { name, value } = e.target;
    setEventData((prevData) => {
      const newData = {
        ...prevData,
        [name]: value,
      };
      if (name === 'start') {
        newData.end = value;
      }
      return newData;
    });
  };

  const handlePositionChange = (e, index) => {
    const newPos = [...eventData.position];
    newPos[index] = e.target.value;
    setEventData((prevData) => ({ ...prevData, position: newPos }));
  };

  const validateFields = (isUpdate = false) => {
    if (!eventData.title) {
      alert('Il titolo è obbligatorio');
      return false;
    }

    if (!isUpdate) {
      const requiredFields = ['time', 'description', 'address', 'start', 'end'];
      for (const field of requiredFields) {
        if (!eventData[field]) {
          alert(`Il campo ${field} è obbligatorio`);
          return false;
        }
      }

      if (!eventData.position[0] || !eventData.position[1]) {
        alert('Latitudine e longitudine sono obbligatorie');
        return false;
      }
    }

    return true;
  };

  const sendRequest = async (method, successMessage) => {
    const formattedData = {
      id: Date.now(),
      title: eventData.title,
      ...(eventData.time && { time: eventData.time }),
      ...(eventData.description && { description: eventData.description }),
      ...(eventData.address && { address: eventData.address }),
      ...(eventData.position[0] && eventData.position[1] && {
        position: [parseFloat(eventData.position[0]), parseFloat(eventData.position[1])],
      }),
      ...(eventData.start && { start: new Date(eventData.start + 'Z').toISOString() }),
      ...(eventData.end && { end: new Date(eventData.end + 'Z').toISOString() }),
      ...(eventData.iconUrl && { iconUrl: eventData.iconUrl }),
      ...(eventData.backgroundColor && { backgroundColor: eventData.backgroundColor }),
    };

    try {
      const response = await fetch('https://anxwjec2ct.eu-central-1.awsapprunner.com/mover/events', {
        method,
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(formattedData),
      });

      if (!response.ok) throw new Error('Errore nella richiesta');

      alert(successMessage);
      setEventData({
        title: '',
        time: '',
        description: '',
        address: '',
        position: ['', ''],
        start: '',
        end: '',
        iconUrl: '',
        backgroundColor: '',
      });
    } catch (error) {
      console.error('Errore:', error);
      alert('Errore nella richiesta');
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!validateFields()) return;
    await sendRequest('POST', 'Evento aggiunto con successo!');
  };

  const handleUpdate = async (e) => {
    e.preventDefault();
    if (!validateFields(true)) return;
    await sendRequest('PUT', 'Evento aggiornato con successo!');
  };

  const handleDelete = async () => {
    if (!deleteTitle) return alert('Inserisci un nome evento');

    try {
      const response = await fetch('https://anxwjec2ct.eu-central-1.awsapprunner.com/mover/events', {
        method: 'DELETE',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ title: deleteTitle }),
      });

      if (!response.ok) throw new Error('Errore nella richiesta');

      alert('Evento eliminato con successo!');
      setDeleteTitle('');
    } catch (error) {
      console.error('Errore:', error);
      alert('Errore nella richiesta');
    }
  };

  const handleCalculate = async () => {
    try {
      const response = await fetch('https://anxwjec2ct.eu-central-1.awsapprunner.com/mover/points', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
      });

      if (!response.ok) throw new Error('Errore nel calcolo dei punti');

      alert('Calcolo avviato con successo!');
    } catch (error) {
      console.error('Errore:', error);
      alert('Errore durante il calcolo');
    }
  };

  const handleTeamChange = (e) => {
    const { name, value } = e.target;
    setTeamData((prev) => ({
      ...prev,
      [name]: value,
    }));
  };

  const handleAddUserChange = (e) => {
    const { name, value } = e.target;
    setAddUserData((prev) => ({
      ...prev,
      [name]: value,
    }));
  };

  const handleAddTeam = async (e) => {
    e.preventDefault();

    if (!teamData.teamName) {
      alert('Il nome team è obbligatorio');
      return;
    }

    const memberNames = teamData.memberNames
      .split(',')
      .map((name) => name.trim())
      .filter(Boolean);

    if (memberNames.length === 0) {
      alert('Inserisci almeno un membro');
      return;
    }

    try {
      const response = await fetch('https://anxwjec2ct.eu-central-1.awsapprunner.com/mover/addTeam', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          teamName: teamData.teamName,
          memberNames,
        }),
      });

      if (!response.ok) throw new Error('Errore nella creazione team');

      alert('Team creato con successo!');
      setTeamData({
        teamName: '',
        memberNames: '',
      });
    } catch (error) {
      console.error('Errore:', error);
      alert('Errore nella creazione team');
    }
  };

  const handleAddUserToTeam = async (e) => {
    e.preventDefault();

    if (!addUserData.teamName || !addUserData.userName) {
      alert('Compila sia teamName che userName');
      return;
    }

    try {
      const response = await fetch('https://anxwjec2ct.eu-central-1.awsapprunner.com/mover/addUserToTeam', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          teamName: addUserData.teamName,
          userName: addUserData.userName,
        }),
      });

      if (!response.ok) throw new Error('Errore nell’aggiunta utente al team');

      alert('Utente aggiunto al team con successo!');
      setAddUserData({
        teamName: '',
        userName: '',
      });
    } catch (error) {
      console.error('Errore:', error);
      alert('Errore nell’aggiunta utente al team');
    }
  };

  return (
    <div className="admin-container">
      <h1 className="admin-title">Pannello di Amministrazione</h1>

      <div className="event-form">
        <h2>Gestisci Evento</h2>
        <form onSubmit={handleSubmit}>
          <input
            type="text"
            name="title"
            placeholder="Titolo (Obbligatorio)"
            value={eventData.title}
            onChange={handleChange}
            required
          />
          <input
            type="text"
            name="time"
            placeholder="Orario (es. 11:00 AM)"
            value={eventData.time}
            onChange={handleChange}
          />
          <textarea
            name="description"
            placeholder="Descrizione"
            value={eventData.description}
            onChange={handleChange}
          />
          <input
            type="text"
            name="address"
            placeholder="Indirizzo"
            value={eventData.address}
            onChange={handleChange}
          />

          <div className="position-inputs">
            <input
              type="number"
              step="any"
              placeholder="Latitudine"
              value={eventData.position[0]}
              onChange={(e) => handlePositionChange(e, 0)}
            />
            <input
              type="number"
              step="any"
              placeholder="Longitudine"
              value={eventData.position[1]}
              onChange={(e) => handlePositionChange(e, 1)}
            />
          </div>

          <input
            type="datetime-local"
            name="start"
            value={eventData.start}
            onChange={handleChange}
          />
          <input
            type="datetime-local"
            name="end"
            value={eventData.end}
            onChange={handleChange}
          />

          <input
            type="text"
            name="iconUrl"
            placeholder="URL Icona"
            value={eventData.iconUrl}
            onChange={handleChange}
          />
          <input
            type="text"
            name="backgroundColor"
            placeholder="Colore di sfondo (es. red, #ff0000)"
            value={eventData.backgroundColor}
            onChange={handleChange}
          />

          <div className="button-group">
            <button type="submit" className="submit-button">Aggiungi Evento</button>
            <button type="button" className="update-button" onClick={handleUpdate}>Aggiorna Evento</button>
          </div>
        </form>
      </div>

      <div className="delete-section">
        <h2>Elimina Evento</h2>
        <input
          type="text"
          placeholder="Nome evento da eliminare"
          value={deleteTitle}
          onChange={(e) => setDeleteTitle(e.target.value)}
        />
        <button className="delete-button" onClick={handleDelete}>Elimina</button>
      </div>

      <div className="calculation-section">
        <h2>Calcolo</h2>
        <button className="calculate-button" onClick={handleCalculate}>Avvia Calcolo</button>
      </div>

      <div className="team-form">
        <h2>Crea Team</h2>
        <form onSubmit={handleAddTeam}>
          <input
            type="text"
            name="teamName"
            placeholder="Nome team"
            value={teamData.teamName}
            onChange={handleTeamChange}
          />
          <input
            type="text"
            name="memberNames"
            placeholder="Membri separati da virgola, es. mover-admin, TestUser2"
            value={teamData.memberNames}
            onChange={handleTeamChange}
          />
          <button type="submit" className="submit-button">Crea Team</button>
        </form>
      </div>

      <div className="team-form">
        <h2>Aggiungi Utente a Team</h2>
        <form onSubmit={handleAddUserToTeam}>
          <input
            type="text"
            name="teamName"
            placeholder="Nome team"
            value={addUserData.teamName}
            onChange={handleAddUserChange}
          />
          <input
            type="text"
            name="userName"
            placeholder="Nome utente"
            value={addUserData.userName}
            onChange={handleAddUserChange}
          />
          <button type="submit" className="submit-button">Aggiungi Utente</button>
        </form>
      </div>

      <div className="scores-section">
        <h2>Punteggi</h2>
        <div className="button-group">
          <button type="button" className="refresh-button" onClick={fetchScores}>
            Ottieni Punteggi
          </button>
          <button type="button" className="refresh-button" onClick={fetchTeams}>
            Ottieni Team
          </button>
        </div>
        
        <h2>Temporanei</h2>
        <ul>
          {displayScores.map((result, index) => (
            <li key={index}>
              {index + 1}. {result.username} {result.gender ? `(${result.gender})` : ''} - {result.finalScore}
            </li>
          ))}
        </ul>
        <h2>Squadre</h2>
        <ul>
          {displayTeams.map((result, index) => (
            <li key={index}>
              {index + 1}. {result.teamName}: {result.finalScore}
            </li>
          ))}
        </ul>
      </div>
    </div>
  );
};

export default AdminPage;