import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useGoogleReCaptcha } from 'react-google-recaptcha-v3';
import './Login.css';
import info from '../assets/info.svg';
import InfoModal from './InfoModal';

const Login = ({ setUser, setSelectedBlocks }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [gender, setGender] = useState('');
  const [isRegistering, setIsRegistering] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const navigate = useNavigate();
  const { executeRecaptcha } = useGoogleReCaptcha();

  
  useEffect(() => {
      // Controlla se l'utente sta utilizzando un dispositivo iOS
      const isIOS = /iPad|iPhone|iPod/.test(navigator.userAgent) && !window.MSStream;
      
      // Funzione per verificare se il sito è in modalità standalone
      const isInStandaloneMode = () => ('standalone' in window.navigator) && (window.navigator.standalone);
      
      if (isIOS && !isInStandaloneMode()) {
        console.log('Su iOS, le notifiche push funzionano solo se il sito è aggiunto alla schermata iniziale.');
        alert('Per ricevere notifiche sugli eventi, clicca sul pulsante condividi e aggiungi alla home il sito.');
      }
  }, []);
  
  useEffect(() => {
    if (!isRegistering) {
      setUsername('');
      setPassword('');
      setGender('');
    }
  }, [isRegistering]);
  
  useEffect(() => {
    const savedUser = localStorage.getItem('user');
    if (savedUser) {
      setUser(JSON.parse(savedUser));
      navigate('/home');
    }
  }, [setUser, navigate]);

  const handleLogin = async () => {
    if (isProcessing) return;
      setIsProcessing(true);
    if (!username || !password) {
      alert('Username e password non possono essere vuoti.');
      setIsProcessing(false);
      return;
    }

    if (username.length < 3) {
      alert('Il nome utente deve essere lungo almeno 3 caratteri.');
      setIsProcessing(false);
      return;
    }

    if (password.length < 8) {
      alert('La password deve essere lunga almeno 8 caratteri.');
      setIsProcessing(false);
      return;
    }

    if (!executeRecaptcha) {
      console.log('Recaptcha non è pronto');
      return;
    }

    const token = await executeRecaptcha('login');
    if (!token) {
      alert('Per favore completa il CAPTCHA.');
      return;
    }

    const payload = { username, password, captchaToken: token };
    // const user = users.find(u => u.username === username && u.password === password);
    // if (user) {
    //   setUser(user);
    //   localStorage.setItem('user', JSON.stringify(user.username));
    //   navigate('/home');
    // } else {
      try {
        const response = await fetch('https://anxwjec2ct.eu-central-1.awsapprunner.com/mover/login', {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
          },
          body: JSON.stringify(payload),
        });

        if (response.status === 401) {
          console.error('Unauthorized access - 401');
          alert('Password errata');
          return; // Esci dalla funzione dopo il reload
        }
        if (response.status === 400) {
          console.error('400');
          alert('Nome utente non esistente, clicca su Registrati');
          return; // Esci dalla funzione dopo il reload
        }
        if (response.ok) {
          const token = await response.text();
          console.log(token);
          localStorage.setItem('token', token);
          const user = { username };
          setUser(user);
          localStorage.setItem('user', JSON.stringify(payload.username)); 
          alert('Login effettuato con successo');
          // Fetch selected blocks after login
          const blocksResponse = await fetch('https://anxwjec2ct.eu-central-1.awsapprunner.com/mover/savedBlocks', {
            method: 'GET',
            headers: {
              'Content-Type': 'application/json',
              'Authorization': `Bearer ${token}`,
              'username' : payload.username
            },
          });

          if (response.status === 401) {
            console.error('Unauthorized access - 401');
            localStorage.clear();
            window.location.reload();
            return; // Esci dalla funzione dopo il reload
          }

          if (blocksResponse.ok) {
            let savedBlocks = await blocksResponse.json();
            if (!savedBlocks || savedBlocks.length === 0) {
              savedBlocks = [];
            }
            // Se non è un array, lo trasformiamo in un array
            if (!Array.isArray(savedBlocks)) {
              savedBlocks = [savedBlocks]; 
            } else {
              savedBlocks = savedBlocks.map(block => block.toString());
            }

            localStorage.setItem(`selectedBlocks-${username}`, JSON.stringify(savedBlocks));
            setSelectedBlocks(savedBlocks); 
          } else {
            console.error('Impossibile recuperare i blocchi salvati');
          }

          // Fetch submitted blocks after login
          const submittedResponse = await fetch('https://anxwjec2ct.eu-central-1.awsapprunner.com/mover/submittedblocks', {
            method: 'GET',
            headers: {
              'Content-Type': 'application/json',
              'Authorization': `Bearer ${token}`,
              'username' : payload.username
            },
          });

          if (response.status === 401) {
            console.error('Unauthorized access - 401');
            localStorage.clear();
            window.location.reload();
            return; // Esci dalla funzione dopo il reload
          }
          if (submittedResponse.ok) {
            let submittedBlocks = await submittedResponse.json();
            if (!submittedBlocks || submittedBlocks.length === 0) {
              submittedBlocks = [];
            }
            // Se non è un array, lo trasformiamo in un array
            if (!Array.isArray(submittedBlocks)) {
                submittedBlocks = [submittedBlocks]; 
            } else {
                submittedBlocks = submittedBlocks.map(block => block.toString());
            }
        
            localStorage.setItem(`submittedBlocks-${username}`, JSON.stringify(submittedBlocks));
        } else {
            console.error('Impossibile recuperare i blocchi inviati');
        }

          navigate('/home');
        } else {
          alert('Login fallito.');
        }
      } catch (error) {
        console.error('Errore durante il login:', error);
      } 
      finally {
          setIsProcessing(false);
        }
      
  };

  const handleRegister = async () => {
    if (isProcessing) return;
      setIsProcessing(true);

    const trimmedUsername = username.trim();
    if (trimmedUsername !== username) {
      alert('Il nome utente contiene spazi all\'inizio o alla fine. Rimuovili.');
      setIsProcessing(false);
      return;
    }

    if (username.includes(' ')) {
      alert('Il nome utente contiene spazi. Rimuovili.');
      setIsProcessing(false);
      return;
    }

    if (!username || !password) {
      alert('Nome utente e password non possono essere vuoti.');
      setIsProcessing(false);
      return;
    }

    if (username.length < 5) {
      alert('Il nome utente deve essere lungo almeno 5 caratteri.');
      setIsProcessing(false);
      return;
    }

    if (password.length < 8) {
      alert('La password deve essere lunga almeno 8 caratteri.');
      setIsProcessing(false);
      return;
    }
    
    if (password !== confirmPassword) {
      alert('Le password non corrispondono.');
      setIsProcessing(false);
      return;
    }

    if (!gender) {
      alert('Seleziona un genere.');
      setIsProcessing(false);
      return;
    }

    if (!executeRecaptcha) {
      console.log('Recaptcha non è pronto');
      return;
    }

    const token = await executeRecaptcha('login');
    if (!token) {
      alert('Per favore completa il CAPTCHA.');
      return;
    }

    const payload = { username, password, gender, captchaToken: token };
  
    try {
      const response = await fetch('https://anxwjec2ct.eu-central-1.awsapprunner.com/mover/register', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(payload),
      });

      if (response.status === 401) {
        console.error('Unauthorized access - 401');
        localStorage.clear();
        window.location.reload();
        return; // Esci dalla funzione dopo il reload
      }
    
  
      if (response.ok) {
        const token = await response.text();
        localStorage.setItem('token', token);
        const user = { username };
        setUser(user);
        localStorage.setItem('user', JSON.stringify(user));
        alert('Registrazione avvenuta con successo');
        setConfirmPassword('');
        navigate('/home');
      } else if (response.status === 400) {
        alert('Nome utente già esistente. Scegli un nome utente diverso.');
      } else {
        alert('Registrazione fallita');
      }
    } catch (error) {
      console.error('Errore durante la registrazione:', error);
    } 
    finally {
        setIsProcessing(false);
      }    
  };

  return (
    <div className="login-container">
      <h2>{isRegistering ? 'Registrati' : 'Accedi'}<InfoModal fromLogin={true}/></h2>
      <h4>{isRegistering ? 'Per favore inserisci il tuo nome e cognome senza spazi. Il nome utente non deve contenere spazi e deve avere almeno 5 caratteri.' : null}</h4>
      <h4>{isRegistering ? 'La password deve essere lunga almeno 8 caratteri. Ricordati i tuoi dati, una volta inseriti sarai direttamente dentro l\'app, buona arrampicata!' : null}</h4>
      <input
        type="text"
        placeholder="Nome utente"
        value={username}
        onChange={(e) => setUsername(e.target.value)}
      />
      <div className="password-container">
        <input
          type={showPassword ? 'text' : 'password'}
          placeholder="Password"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
        />
        <button
          type="button"
          className='password-button'
          onClick={() => setShowPassword(!showPassword)}
        >
          {showPassword ? 'Nascondi' : 'Mostra'}
        </button>
      </div>
      {isRegistering && (
        <div className="password-container">
          <input
            type={showPassword ? 'text' : 'password'}
            placeholder="Conferma password"
            value={confirmPassword}
            onChange={(e) => setConfirmPassword(e.target.value)}
          />
        </div>
      )}
      {isRegistering && (
        <select
          value={gender}
          onChange={(e) => setGender(e.target.value)}
          className="gender-dropdown"
        >
          <option value="">Seleziona genere</option>
          <option value="M">Maschio</option>
          <option value="F">Femmina</option>
        </select>
      )}
      {isRegistering ? (
        <>
          <button onClick={handleRegister} disabled={isProcessing}>Registrati</button>
          <button onClick={() => setIsRegistering(false)} disabled={isProcessing}>Torna al login</button>
        </>
      ) : (
        <>
          <button onClick={handleLogin} disabled={isProcessing}>Accedi</button>
          <button onClick={() => setIsRegistering(true)} disabled={isProcessing}>Registrati</button>
        </>
      )}
      <small>Questo sito è protetto da reCAPTCHA e si applicano la <a className="link" href="https://policies.google.com/privacy">Privacy Policy</a> e i <a className="link" href="https://policies.google.com/terms">Termini di servizio</a> di Google.</small>
    </div>
  );
};

export default Login;
