import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Route, Routes, Navigate } from 'react-router-dom';
import { GoogleReCaptchaProvider } from 'react-google-recaptcha-v3'
import Login from './components/Login';
import SectionList from './components/SectionList';
import Map from './components/Map';
import Menu from './components/Menu';
import Regolamento from './components/Regolamento';
import Policy from './components/Policy';
import Results from './components/Results';
import AdminPage from './components/Admin';
import Programma from './components/Programma';
import Spinner from './components/Spinner';
import { appConfig } from './config';
import { sectionsData } from './sectionsData'; // Importa sectionsData dal file separato
import { sendApiRequest } from './apiQueue'; // Importa la funzione sendApiRequest
import './App.css';

const App = () => {
  const [user, setUser] = useState(() => {
    const savedUser = localStorage.getItem('user');
    return savedUser ? JSON.parse(savedUser) : null;
  });

  const [selectedBlocks, setSelectedBlocks] = useState(() => {
    const savedSelections = localStorage.getItem(`selectedBlocks-${user?.username}`);
    return savedSelections ? JSON.parse(savedSelections) : [];
  });

  const [showWarning, setShowWarning] = useState(false);
  const [isAppAvailable, setIsAppAvailable] = useState(true);
  const [isAppStarted, setIsAppStarted] = useState(false);
  const [timeRemaining, setTimeRemaining] = useState('');
  const [eventMessage, setEventMessage] = useState(null);
  const [responsesSent, setResponsesSent] = useState(false);
  const [additionalPins, setAdditionalPins] = useState([]);
  const [activePins, setActivePins] = useState([]);
  const [loading, setLoading] = useState(true);
  const [deferredPrompt, setDeferredPrompt] = useState(null); // Salva l'evento 'beforeinstallprompt'
  const [showInstallButton, setShowInstallButton] = useState(false); // Stato per il bottone di installazione
  const [notificationSent, setNotificationSent] = useState(() => {
    return localStorage.getItem('notificationSent') === 'true';
  }); // Nuovo stato per il flag

  useEffect(() => {
    if (user) {
      localStorage.setItem('user', JSON.stringify(user));
    }
  }, [user]);

  useEffect(() => {
    if (user) {
      localStorage.setItem(`selectedBlocks-${user.username}`, JSON.stringify(selectedBlocks));
    }
  }, [selectedBlocks, user]);

  useEffect(() => {
    // Ascolta l'evento 'beforeinstallprompt'
    const handleBeforeInstallPrompt = (e) => {
      e.preventDefault(); // Previeni la visualizzazione automatica del prompt
      setDeferredPrompt(e); // Salva l'evento per utilizzarlo più tardi
      setShowInstallButton(true); // Mostra il bottone di installazione
    };

    window.addEventListener('beforeinstallprompt', handleBeforeInstallPrompt);

    // Cleanup: rimuovi l'evento quando il componente viene smontato
    return () => {
      window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
    };
  }, []);

  const handleInstallClick = () => {
    if (deferredPrompt) {
      deferredPrompt.prompt(); // Mostra il prompt di installazione
      deferredPrompt.userChoice.then((choiceResult) => {
        if (choiceResult.outcome === 'accepted') {
          console.log('PWA installata con successo!');
        } else {
          console.log('Installazione PWA rifiutata.');
        }
        setDeferredPrompt(null); // Resetta l'evento dopo l'uso
        setShowInstallButton(false); // Nasconde il bottone di installazione
      });
    }
  };

  const waitForImagesToLoad = () => {
    return new Promise(resolve => {
      const images = Array.from(document.images);
      if (images.length === 0) {
        resolve();
        return;
      }

      let loadedCount = 0;
      const checkLoaded = () => {
        loadedCount++;
        if (loadedCount === images.length) {
          resolve();
        }
      };

      images.forEach(img => {
        if (img.complete) {
          checkLoaded();
        } else {
          img.addEventListener('load', checkLoaded);
          img.addEventListener('error', checkLoaded);
        }
      });
    });
  };
  
  const handleCheckboxChange = (blockName) => {
    setSelectedBlocks(prevSelectedBlocks => {
      // Verifica se il blocco è già presente
      if (prevSelectedBlocks.includes(blockName)) {
        // Rimuovi il blocco dall'array
        return prevSelectedBlocks.filter(block => block !== blockName);
      } else {
        // Aggiungi il nuovo blocco mantenendo quelli esistenti
        return [...prevSelectedBlocks, blockName];
      }
    });
  };
  
  // useEffect(() => {
  //   if ("serviceWorker" in navigator) {
  //     window.addEventListener("load", () => {
  //       navigator.serviceWorker
  //         .register("/service-worker.js")
  //         .then(registration => {
  //           console.log("Service Worker registered with scope:", registration.scope);
  //         })
  //         .catch(error => {
  //           console.error("Service Worker registration failed:", error);
  //         });
  //     });
  //   }
  // }, []);

  useEffect(() => {
    const fetchAdditionalPins = async () => {
      try {
        console.log('Fetching additional pins...');
        const response = await fetch('https://anxwjec2ct.eu-central-1.awsapprunner.com/mover/events');

        if (response.status === 401) {
          console.error('Unauthorized access - 401');
          localStorage.clear();
          window.location.reload();
          return; // Esci dalla funzione dopo il reload
        }
      
        const data = await response.json();
        console.log('Data fetched:', data);
        setAdditionalPins(data);
        await waitForImagesToLoad();
        // Calculate activePins
        const now = new Date();
        console.log('Current time:', now);
        const active = data.filter(pin => {
          const title = pin.title;
          const description = pin.description;
          const address = pin.address;
          const time = pin.time;
          const position = Array.isArray(pin.position) ? pin.position : [pin.position];
          const startTime = new Date(pin.start);
          const endTime = new Date(pin.end);
          const backgroundColor = pin.backgroundColor;
          const iconUrl = pin.iconUrl;
          console.log(`Processing pin: 
            Title: ${title}, 
            Description: ${description}, 
            Time: ${time},
            Address: ${address}, 
            Position: ${position}, 
            Start: ${startTime}, 
            End: ${endTime}, 
            Background Color: ${backgroundColor}, 
            Icon URL: ${iconUrl}`);
            return now >= new Date(startTime.getTime() - 35 * 60 * 1000) && now <= endTime;
        });
        console.log('Active pins:', active);
        setActivePins(active);
      } catch (error) {
        console.error('Error fetching additional pins:', error);
      } finally {
        setLoading(false);
      }
    };
  
    fetchAdditionalPins(); // Esegui subito la fetch
  
    const fetchInterval = setInterval(fetchAdditionalPins, 5 * 60 * 1000); // Aggiorna ogni 5 minuti
  
    const cleanupInterval = setInterval(() => {
      const now = new Date();
      setActivePins(prevActivePins => prevActivePins.filter(pin => new Date(pin.end) >= now));
    }, 1000 * 60); // Controllo attivo ogni minuto
  
    return () => {
      clearInterval(fetchInterval);
      clearInterval(cleanupInterval);
    };
  }, []);

  useEffect(() => {
    const sendNotification = (title, body, tag) => {
      console.log('Sending notification:', title, body, tag); // Aggiungi questo per il debug
      navigator.serviceWorker.ready.then(registration => {
        registration.showNotification(title, {
          body,
          icon: '/logo192.png',
          tag // Tag per evitare notifiche duplicate
        });
      });
    };

    const checkAndSendNotifications = () => {
      activePins.forEach(pin => {
        const title = pin.title.replace(/(_1|_2|_3)$/, '');
        // Inizializza le proprietà notified30 e notified10 se non esistono
        if (pin.notified30 === undefined) pin.notified30 = false;
        if (pin.notified10 === undefined) pin.notified10 = false;

        const now = new Date();
        const startTime = new Date(pin.start);
        const endTime = new Date(pin.end);
        const notificationTime1 = new Date(startTime.getTime() - 30 * 60 * 1000);
        const notificationTime2 = new Date(startTime.getTime() - 10 * 60 * 1000);

        if (now >= notificationTime1 && now < startTime && now <= endTime && !pin.notified30) {
          sendNotification(title, `L'evento "${title}" inizierà tra poco!`, pin.title);
          pin.notified30 = true; // Segna che la notifica a 30 minuti è stata inviata
        }
        
        if (now >= notificationTime2 && now < startTime && now <= endTime && !pin.notified10) {
          sendNotification(title, `L'evento "${title}" inizierà tra poco!`, pin.title);
          pin.notified10 = true; // Segna che la notifica a 10 minuti è stata inviata
        }
      });
    };

    if (activePins.length > 0) {
      checkAndSendNotifications();
    }
    const interval = setInterval(checkAndSendNotifications, 60 * 1000); // Controllo ogni minuto

    return () => clearInterval(interval);
  }, [activePins]);

  useEffect(() => {
    const checkNotification = () => {
      const now = new Date();
      const deadlineWithBuffer = new Date(appConfig.deadline.getTime() + 30 * 60 * 1000);

      if (isAppStarted && !isAppAvailable && now > deadlineWithBuffer && !notificationSent) {
        if (navigator.serviceWorker) {
          navigator.serviceWorker.ready.then(registration => {
            registration.showNotification("Classifica aggiornata!", {
              body: "La classifica è disponibile!",
              icon: "/logo192.png",
              tag: "score-update" // Tag per evitare notifiche duplicate
            });
          });
        }
        setNotificationSent(true); // Imposta il flag a true dopo aver inviato la notifica
        localStorage.setItem('notificationSent', 'true'); // Salva il flag nel localStorage
      }
    };

    // Esegui il controllo IMMEDIATAMENTE al primo render
    checkNotification();
    // Esegui il controllo ogni minuto per aggiornamenti successivi
    const interval = setInterval(checkNotification, 1000 * 60);

    return () => clearInterval(interval); // Cleanup su unmount
  }, [notificationSent]);

  useEffect(() => {
    const checkAppDeadline = () => {
      const now = new Date(); // Ottieni l'ora corrente nel fuso orario di Roma
      const timeDiff = appConfig.deadline - now;

      if (timeDiff <= 0) {
        setShowWarning(false); // Nasconde il warning dopo la deadline
        setIsAppAvailable(false);
        return;
      }

      // Calcola il tempo rimanente in minuti e secondi
      const minutesRemaining = Math.floor(timeDiff / (1000 * 60));
      const secondsRemaining = Math.floor((timeDiff % (1000 * 60)) / 1000);
      setTimeRemaining(`${minutesRemaining}m ${secondsRemaining}s`);

      // Mostra il warning se siamo negli ultimi 30 minuti
      if (minutesRemaining < 30) {
        setShowWarning(true);
      }
    };

    const checkAppStart = () => {
      const now = new Date(); // Ottieni l'ora corrente nel fuso orario di Roma
      const startDiff = now - appConfig.start;

      if (startDiff >= 0) {
        setIsAppStarted(true); // Imposta il valore booleano a true se l'orario attuale è superiore a appConfig.start
      } else {
        setIsAppStarted(false); // Imposta il valore booleano a false se l'orario attuale è inferiore a appConfig.start
      }
    };

    checkAppDeadline(); // Esegui subito il primo controllo
    checkAppStart(); // Esegui subito il primo controllo per appConfig.start
    const interval = setInterval(() => {
      checkAppDeadline();
      checkAppStart();
    }, 5 * 60 * 1000); // Controllo ogni 5 minuti

    return () => clearInterval(interval); // Cleanup su unmount
  }, []);

  const handleSubmit = async () => {
    const blocksDone = selectedBlocks;
    if (!isAppAvailable) {
      alert("Non è più possibile inviare i blocchi, la gara è finita!");
      return;
    }
    try {
      const token = localStorage.getItem('token');
      const response = await fetch('https://anxwjec2ct.eu-central-1.awsapprunner.com/mover/submit', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`,
        },
        body: JSON.stringify({ username: user.username, blocksDone }),
      });
      
      if (response.status === 401) {
        console.error('Unauthorized access - 401');
        localStorage.clear();
        window.location.reload();
        return; // Esci dalla funzione dopo il reload
      }
    
      if (!response.ok) {
        throw new Error('Network response was not ok');
      }
    } catch (error) {
      console.error('There was a problem with the fetch operation:', error);
    }
  };

  const handleEventMessage = (message) => {
    setEventMessage(message);
    setTimeout(() => setEventMessage(null), 5000); // Nasconde il messaggio dopo 5 secondi
  };

  const closeWarning = () => {
    setShowWarning(false);
  };

  if (loading) {
      return <Spinner />;
    }
    
  return (
    <GoogleReCaptchaProvider 
      reCaptchaKey="6LeUbxIrAAAAAJvIhCRInjXd6Ziggu19SEDrcUuj"
      language='it'
      container={{
        element: "recaptcha-container",
        parameters: {
          badge: "inline", 
        },
      }}
    >
    <Router>
      <div className="app-wrapper">
        <div id="recaptcha-container" className='grecaptcha-badge'></div>
        <div className={`app-container ${showWarning ? 'blurred' : ''}`}>
          {user && <Menu />}
          {eventMessage && (
            <div className={`event-popup ${eventMessage.type}`}>
              {eventMessage.text}
            </div>
          )}
          <Routes>
            <Route path="/" element={<Login setUser={setUser} setSelectedBlocks={setSelectedBlocks} />} />
            <Route path="/sections" element={user ? <SectionList user={user} selectedBlocks={selectedBlocks} onCheckboxChange={handleCheckboxChange} onSubmit={handleSubmit} showWarning={showWarning} timeRemaining={timeRemaining} responsesSent={responsesSent} isAppAvailable={isAppAvailable} isAppStarted={isAppStarted}/> : <Login setUser={setUser} setSelectedBlocks={setSelectedBlocks} />} />
            <Route path="/map" element={user ? <Map user={user} sections={sectionsData} selectedBlocks={selectedBlocks} onCheckboxChange={handleCheckboxChange} showWarning={showWarning} timeRemaining={timeRemaining} onEventMessage={handleEventMessage} responsesSent={responsesSent} isAppAvailable={isAppAvailable} additionalPins={activePins} isAppStarted={isAppStarted}/> : <Login setUser={setUser} setSelectedBlocks={setSelectedBlocks} />} />
            <Route path="/regolamento" element={user ? <Regolamento /> : <Login setUser={setUser} setSelectedBlocks={setSelectedBlocks} />} /> {/* Aggiunta la rotta per Regolamento */}
            <Route path="/policy" element={user ? <Policy />: <Login setUser={setUser} setSelectedBlocks={setSelectedBlocks} />} />{/* Aggiunta la rotta per Policy */}
            <Route path="/results" element={user ? <Results isAppAvailable={isAppAvailable}/>: <Login setUser={setUser} setSelectedBlocks={setSelectedBlocks} />} /> {/* Aggiunta la rotta per Results */}
            <Route path="/home" element={user ? <Navigate to="/map" /> : <Login setUser={setUser} setSelectedBlocks={setSelectedBlocks} />} />
            <Route path="/adminpage" element={user ? <AdminPage />: <Login setUser={setUser} setSelectedBlocks={setSelectedBlocks} />} />
            <Route path="/program" element={user ? <Programma additionalPins={additionalPins} user={user}/>: <Login setUser={setUser} setSelectedBlocks={setSelectedBlocks} />} />
          </Routes>
          {/* Bottone per installare l'app */}
          {showInstallButton && (
            <button className="install-button" onClick={handleInstallClick}>
              Installa App
            </button>
          )}
        </div>
        {showWarning && (
          <div className="warning-overlay" onClick={closeWarning}>
            <div className="warning-popup" onClick={(e) => e.stopPropagation()}>
              <button className="close-button" onClick={closeWarning}>x</button>
              Affrettati a inviare i blocchi, la gara sta per finire! Tempo rimanente: {timeRemaining}
            </div>
          </div>
        )}
      </div>
    </Router>
    </GoogleReCaptchaProvider>
  );
};

export default App;